import React, { useState, useEffect, useCallback } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { booksAPI, finesAPI, libraryCardsAPI, issuesAPI } from '../services/api';

// ─────────────────────────────────────────────────────────────
// HELPERS
// ─────────────────────────────────────────────────────────────

/**
 * Safely extracts an array from common API response shapes:
 *   res.data.data  |  res.data  |  res  |  []
 */
const extractArray = (res) => {
  const payload = res?.data?.data ?? res?.data ?? res ?? [];
  return Array.isArray(payload) ? payload : [];
};

/**
 * Safely extracts a single object (non-array) from the response.
 */
const extractObject = (res) => {
  const payload = res?.data?.data ?? res?.data ?? null;
  return Array.isArray(payload) ? null : payload ?? null;
};

/**
 * Returns the fine amount regardless of field name used by the backend.
 */
const getFineAmount = (fine) =>
  Number(fine?.amount ?? fine?.fineAmount ?? fine?.fine_amount ?? 0);

/**
 * Returns a lowercase, trimmed status string for safe comparison.
 */
const normalizeStatus = (val) => (val ?? '').toString().trim().toLowerCase();

// ─────────────────────────────────────────────────────────────
// SUB-COMPONENTS
// ─────────────────────────────────────────────────────────────

const StatCard = ({ icon, color, value, label }) => (
  <div className="col-sm-6 col-lg-3">
    <div className="stat-card">
      <div className={`stat-icon ${color}`}>
        <i className={`bi ${icon}`}></i>
      </div>
      <div>
        <div className="stat-value">{value}</div>
        <div className="stat-label">{label}</div>
      </div>
    </div>
  </div>
);

const QuickAction = ({ to, icon, label, color }) => (
  <Link
    to={to}
    className="lib-card p-3 d-flex align-items-center gap-3 text-decoration-none"
    style={{ color: 'var(--text-main)', transition: 'transform .2s' }}
    onMouseEnter={(e) => (e.currentTarget.style.transform = 'translateY(-2px)')}
    onMouseLeave={(e) => (e.currentTarget.style.transform = 'translateY(0)')}
  >
    <div className={`stat-icon ${color}`} style={{ flexShrink: 0 }}>
      <i className={`bi ${icon}`}></i>
    </div>
    <span style={{ fontWeight: 500, fontSize: '.92rem' }}>{label}</span>
    <i
      className="bi bi-chevron-right ms-auto text-muted"
      style={{ fontSize: '.75rem' }}
    ></i>
  </Link>
);

const EmptyRow = ({ colSpan, message, linkTo, linkText }) => (
  <tr>
    <td colSpan={colSpan} className="text-center text-muted py-3">
      {message}
      {linkTo && linkText && (
        <>
          {' '}
          <Link to={linkTo}>{linkText}</Link>
        </>
      )}
    </td>
  </tr>
);

// ─────────────────────────────────────────────────────────────
// MAIN COMPONENT
// ─────────────────────────────────────────────────────────────

const DashboardPage = () => {
  const { currentUser } = useAuth();
  const role = currentUser?.role;

  const [loading, setLoading] = useState(true);
  const [error, setError]     = useState(null);
  const [data, setData]       = useState({
    books:    [],
    fines:    [],
    requests: [],
    myCard:   null,
    issues:   [],
  });

  // ── Data fetching ───────────────────────────────────────────
  const fetchDashboardData = useCallback(async () => {
    setLoading(true);
    setError(null);

    try {
      const booksRes = await booksAPI.getAll();
      const books    = extractArray(booksRes);

      if (role === 'Student') {
        const [finesRes, cardRes, issuesRes] = await Promise.all([
          finesAPI.getMyFines(),
          libraryCardsAPI.getMyCard().catch((err) => {
            // 404 simply means no card yet — treat as null, don't throw
            if (err?.statusCode === 404 || err?.response?.status === 404)
              return null;
            throw err;
          }),
          issuesAPI.getAll(),
        ]);

        setData({
          books,
          fines:    extractArray(finesRes),
          myCard:   extractObject(cardRes),
          requests: [],
          issues:   extractArray(issuesRes),
        });
      } else {
        // Librarian or Admin
        const [finesRes, cardsRes, issuesRes] = await Promise.all([
          finesAPI.getAll(),
          libraryCardsAPI.getAll(),
          issuesAPI.getAll(),
        ]);

        setData({
          books,
          fines:    extractArray(finesRes),
          requests: extractArray(cardsRes),
          myCard:   null,
          issues:   extractArray(issuesRes),
        });
      }
    } catch (err) {
      console.error('Dashboard fetch error:', err);
      setError('Failed to load dashboard data. Please try again.');
    } finally {
      setLoading(false);
    }
  }, [role]);

  useEffect(() => {
    if (role) fetchDashboardData();
  }, [role, fetchDashboardData]);

  // ── Approve / Reject handlers (state-based, no reload) ─────
  const handleApprove = async (id) => {
    try {
      await libraryCardsAPI.approve(id);
      setData((prev) => ({
        ...prev,
        requests: prev.requests.map((r) =>
          r._id === id ? { ...r, status: role === 'Admin' ? 'approved' : 'approved by librarian' } : r
        ),
      }));
    } catch (err) {
      alert(err?.message || 'Approval failed. Please try again.');
    }
  };

  const handleReject = async (id) => {
    const reason = prompt('Enter rejection reason:');
    if (!reason) return;
    try {
      await libraryCardsAPI.reject(id, reason);
      setData((prev) => ({
        ...prev,
        requests: prev.requests.map((r) =>
          r._id === id ? { ...r, status: 'rejected' } : r
        ),
      }));
    } catch (err) {
      alert(err?.message || 'Rejection failed. Please try again.');
    }
  };

  // ── Loading / Error states ──────────────────────────────────
  if (loading)
    return (
      <div className="text-center py-5">
        <div className="spinner-border text-primary"></div>
        <p className="mt-2 text-muted">Loading dashboard…</p>
      </div>
    );

  if (error)
    return (
      <div className="text-center py-5">
        <p className="text-danger">{error}</p>
        <button className="btn btn-lib-primary mt-2" onClick={fetchDashboardData}>
          Retry
        </button>
      </div>
    );

  // ── Derived values (all safe) ───────────────────────────────
  const booksArray    = Array.isArray(data.books)    ? data.books    : [];
  const finesArray    = Array.isArray(data.fines)    ? data.fines    : [];
  const issuesArray   = Array.isArray(data.issues)   ? data.issues   : [];
  const requestsArray = Array.isArray(data.requests) ? data.requests : [];

  const unpaidFines      = finesArray.filter((f) => normalizeStatus(f.status) === 'unpaid');
  const totalUnpaidAmt   = unpaidFines.reduce((sum, f) => sum + getFineAmount(f), 0);

  // availableCopies OR available (handle both field names)
  const availableBooks   = booksArray.filter(
    (b) => (b.availableCopies ?? b.available ?? 0) > 0
  ).length;

  const activeIssues     = issuesArray.filter((i) => !i.returnDate).length;
  const pendingRequests  = requestsArray.filter((r) => normalizeStatus(r.status) === 'pending').length;
  const approvedRequests = requestsArray.filter((r) => normalizeStatus(r.status) === 'approved').length;
  const awaitingFinalApproval = requestsArray.filter(
    (r) => normalizeStatus(r.status) === 'approved by librarian'
  );

  // ── Render ──────────────────────────────────────────────────
  return (
    <div className="page-wrapper">
      <div className="container">

        {/* Header */}
        <div className="d-flex align-items-center gap-3 mb-4 flex-wrap">
          <div
            style={{
              width: 54, height: 54, borderRadius: '50%',
              background: 'var(--primary)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
            }}
          >
            <i className="bi bi-person-fill text-white" style={{ fontSize: '1.4rem' }}></i>
          </div>
          <div>
            <h2 className="section-title mb-0">
              Hello, {currentUser?.name?.split(' ')[0] ?? 'User'}! 👋
            </h2>
            <span className={`badge-role badge-${(role ?? '').toLowerCase()}`}>
              {role} Dashboard
            </span>
          </div>
        </div>

        {/* ══════════ STUDENT ══════════ */}
        {role === 'Student' && (
          <>
            <div className="row g-3 mb-4">
              <StatCard icon="bi-journals"       color="red"   value={availableBooks}  label="Books Available" />
              <StatCard icon="bi-credit-card"    color="gold"  value={data.myCard ? 1 : 0} label="Library Card" />
              <StatCard icon="bi-currency-rupee" color="green" value={`₹${totalUnpaidAmt}`} label="Unpaid Fines" />
              <StatCard icon="bi-check-circle"   color="blue"  value={activeIssues}    label="Active Issues" />
            </div>

            <div className="mb-4">
              <h5 className="section-title mb-2" style={{ fontSize: '1.1rem' }}>Quick Actions</h5>
              <div className="row g-3">
                <div className="col-md-4">
                  <QuickAction to="/books"        icon="bi-search"         color="red"   label="Browse Books" />
                </div>
                <div className="col-md-4">
                  <QuickAction to="/request-card" icon="bi-credit-card"    color="gold"  label="Library Card Status" />
                </div>
                <div className="col-md-4">
                  <QuickAction to="/fines"        icon="bi-currency-rupee" color="green" label="View My Fines" />
                </div>
              </div>
            </div>

            <div className="lib-card">
              <div className="lib-card-header">
                <h5><i className="bi bi-list-check me-2"></i>My Currently Issued Books</h5>
              </div>
              <div className="table-responsive p-0">
                <table className="lib-table">
                  <thead>
                    <tr><th>#</th><th>Book</th><th>Issue Date</th><th>Due Date</th></tr>
                  </thead>
                  <tbody>
                    {activeIssues === 0 ? (
                      <EmptyRow
                        colSpan={4}
                        message="No active issued books."
                        linkTo="/books"
                        linkText="Browse books"
                      />
                    ) : (
                      issuesArray
                        .filter((r) => !r.returnDate)
                        .map((r, i) => (
                          <tr key={r._id ?? i}>
                            <td>{i + 1}</td>
                            <td>{r.book?.title ?? 'Unknown'}</td>
                            <td>
                              {r.issueDate
                                ? new Date(r.issueDate).toLocaleDateString()
                                : 'N/A'}
                            </td>
                            <td style={{ color: 'var(--danger)' }}>
                              {r.dueDate
                                ? new Date(r.dueDate).toLocaleDateString()
                                : 'N/A'}
                            </td>
                          </tr>
                        ))
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </>
        )}

        {/* ══════════ LIBRARIAN ══════════ */}
        {role === 'Librarian' && (
          <>
            <div className="row g-3 mb-4">
              <StatCard icon="bi-journals"            color="red"   value={booksArray.length}  label="Total Books" />
              <StatCard icon="bi-clock-history"       color="gold"  value={pendingRequests}    label="Pending Cards" />
              <StatCard icon="bi-check-circle"        color="green" value={approvedRequests}   label="Approved Cards" />
              <StatCard icon="bi-exclamation-triangle" color="blue" value={`₹${totalUnpaidAmt}`} label="Unpaid Fines" />
            </div>

            <div className="row g-3 mb-4">
              <div className="col-md-6">
                <QuickAction to="/books" icon="bi-journals"        color="red"  label="Manage Book Catalog" />
              </div>
              <div className="col-md-6">
                <QuickAction to="/fines" icon="bi-currency-rupee"  color="gold" label="Fine Records" />
              </div>
            </div>

            <div className="lib-card">
              <div className="lib-card-header">
                <h5><i className="bi bi-inbox me-2"></i>Library Card Applications</h5>
              </div>
              <div className="table-responsive">
                <table className="lib-table">
                  <thead>
                    <tr>
                      <th>#</th><th>Student</th><th>Course</th>
                      <th>Branch</th><th>Date</th><th>Status</th><th>Action</th>
                    </tr>
                  </thead>
                  <tbody>
                    {requestsArray.length === 0 ? (
                      <EmptyRow colSpan={7} message="No applications found." />
                    ) : (
                      requestsArray.map((r, i) => (
                        <tr key={r._id ?? i}>
                          <td>{i + 1}</td>
                          <td>{r.student?.name ?? 'N/A'}</td>
                          <td>{r.course  ?? 'N/A'}</td>
                          <td>{r.branch  ?? 'N/A'}</td>
                          <td>
                            {r.createdAt
                              ? new Date(r.createdAt).toLocaleDateString()
                              : 'N/A'}
                          </td>
                          <td>
                            <span
                              className={`badge-role badge-${normalizeStatus(r.status).replace(/\s+/g, '-')}`}
                            >
                              {r.status ?? 'unknown'}
                            </span>
                          </td>
                          <td>
                            {normalizeStatus(r.status) === 'pending' && (
                              <>
                                <button
                                  className="btn btn-sm btn-lib-primary me-1"
                                  onClick={() => handleApprove(r._id)}
                                >
                                  Approve
                                </button>
                                <button
                                  className="btn btn-sm btn-lib-secondary"
                                  onClick={() => handleReject(r._id)}
                                >
                                  Reject
                                </button>
                              </>
                            )}
                          </td>
                        </tr>
                      ))
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </>
        )}

        {/* ══════════ ADMIN ══════════ */}
        {role === 'Admin' && (
          <>
            <div className="row g-3 mb-4">
              <StatCard icon="bi-people"         color="red"   value="Admin View"          label="System User" />
              <StatCard icon="bi-journals"       color="gold"  value={booksArray.length}   label="Total Books" />
              <StatCard icon="bi-credit-card"    color="green" value={requestsArray.length} label="Total Cards" />
              <StatCard icon="bi-currency-rupee" color="blue"  value={`₹${totalUnpaidAmt}`} label="Pending Fines" />
            </div>

            <div className="row g-3 mb-4">
              <div className="col-md-4">
                <QuickAction to="/books"        icon="bi-journals"       color="red"   label="Manage Books" />
              </div>
              <div className="col-md-4">
                <QuickAction to="/fines"        icon="bi-currency-rupee" color="gold"  label="Fine Management" />
              </div>
              <div className="col-md-4">
                <QuickAction to="/request-card" icon="bi-credit-card"    color="green" label="Final Card Approvals" />
              </div>
            </div>

            <div className="lib-card">
              <div className="lib-card-header">
                <h5><i className="bi bi-shield-check me-2"></i>Final Approval Required (Admin)</h5>
              </div>
              <div className="table-responsive">
                <table className="lib-table">
                  <thead>
                    <tr><th>#</th><th>Student</th><th>Status</th><th>Date</th><th>Action</th></tr>
                  </thead>
                  <tbody>
                    {awaitingFinalApproval.length === 0 ? (
                      <EmptyRow colSpan={5} message="No cards waiting for final approval." />
                    ) : (
                      awaitingFinalApproval.map((r, i) => (
                        <tr key={r._id ?? i}>
                          <td>{i + 1}</td>
                          <td>{r.student?.name ?? 'N/A'}</td>
                          <td>
                            <span className="badge-role badge-pending">
                              Approved by Librarian
                            </span>
                          </td>
                          <td>
                            {r.createdAt
                              ? new Date(r.createdAt).toLocaleDateString()
                              : 'N/A'}
                          </td>
                          <td>
                            <button
                              className="btn btn-sm btn-lib-primary me-1"
                              onClick={() => handleApprove(r._id)}
                            >
                              Final Approve
                            </button>
                            <button
                              className="btn btn-sm btn-lib-secondary"
                              onClick={() => handleReject(r._id)}
                            >
                              Final Reject
                            </button>
                          </td>
                        </tr>
                      ))
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </>
        )}

      </div>
    </div>
  );
};

export default DashboardPage;
